                className={`px-4 py-2 rounded-full text-[10px] font-black uppercase tracking-[0.2em] transition-all duration-300 ${
                  currentView === s.id
                    ? 'bg-[#CBA76B] text-[#0b3b52]'
                    : `${isTransparentHeader ? 'text-white' : 'text-[#0b3b52]'} hover:bg-[#f7f0e3]`
                }`}
              >
                {s.label}
              </button>
            ))}
          </nav>

