import React, { useState, useEffect, useMemo, memo, useCallback, useRef } from 'react';
import { translations } from './translations.ts';
import { Language, TranslationStrings } from './types.ts';
import { LanguageToggle } from './components/LanguageToggle.tsx';
import { CookieConsent } from './components/CookieConsent.tsx';
import { createChatSession } from './services/geminiService.ts';

// Fix: Declaring google property on Window to resolve TypeScript errors for Google Maps API access.
declare global {
  interface Window {
    google: any;
  }
}

type View = 'inicio' | 'hospedaje' | 'restaurante' | 'experiencias' | 'legal';

// --- COMPONENTE DE ASISTENTE KA'LA ---
const AssistantChat = memo(({ t, lang }: { t: TranslationStrings, lang: Language }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState<{role: 'user' | 'model', text: string}[]>([]);
  const [input, setInput] = useState('');
  const [isThinking, setIsThinking] = useState(false);
  const chatEndRef = useRef<HTMLDivElement>(null);

  const chatSession = useMemo(() => createChatSession(lang), [lang]);

  const scrollToBottom = () => {
    chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    if (isOpen && messages.length === 0) {
      setMessages([{ role: 'model', text: t.assistant.greeting }]);
    }
    scrollToBottom();
  }, [isOpen, messages, t]);

  const handleSend = async () => {
    if (!input.trim() || isThinking) return;

    const userMsg = input.trim();
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setIsThinking(true);

    try {
      const result = await chatSession.sendMessage({ message: userMsg });
      setMessages(prev => [...prev, { role: 'model', text: result.text || '' }]);
    } catch (error) {
      console.error("Ka'la error:", error);
      setMessages(prev => [...prev, { role: 'model', text: "Lo siento, el mar está algo picado ahora. ¿Puedes repetir?" }]);
    } finally {
      setIsThinking(false);
    }
  };

  return (
    <div className="fixed bottom-6 right-6 z-[100] flex flex-col items-end">
      {isOpen && (
        <div className="mb-4 w-[320px] md:w-[380px] h-[450px] bg-white/90 backdrop-blur-2xl rounded-[2.5rem] shadow-2xl border border-white/40 overflow-hidden flex flex-col animate-reveal">
          <div className="p-6 bg-[#0b3b52] text-white flex justify-between items-center">
            <div className="flex items-center gap-3">
              <div className="w-10 h-10 rounded-full bg-[#CBA76B] flex items-center justify-center text-[#0b3b52] font-black text-xs shadow-inner">K</div>
              <div>
                <h4 className="text-sm font-black uppercase tracking-widest">Ka'la</h4>
                <p className="text-[10px] text-white/60 uppercase font-bold tracking-tighter">Guía Apalanchii</p>
              </div>
            </div>
            <button onClick={() => setIsOpen(false)} className="text-white/40 hover:text-white transition-colors">
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
            </button>
          </div>

          <div className="flex-1 overflow-y-auto p-6 space-y-4">
            {messages.map((m, i) => (
              <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[85%] px-4 py-3 rounded-2xl text-xs leading-relaxed ${
                  m.role === 'user' 
                  ? 'bg-[#1f7a8c] text-white rounded-tr-none' 
                  : 'bg-slate-100 text-slate-700 rounded-tl-none font-medium'
                }`}>
                  {m.text}
                </div>
              </div>
            ))}
            {isThinking && (
              <div className="flex justify-start">
                <div className="bg-slate-100 px-4 py-2 rounded-2xl rounded-tl-none flex gap-1">
                  <div className="w-1 h-1 bg-slate-400 rounded-full animate-bounce"></div>
                  <div className="w-1 h-1 bg-slate-400 rounded-full animate-bounce [animation-delay:0.2s]"></div>
                  <div className="w-1 h-1 bg-slate-400 rounded-full animate-bounce [animation-delay:0.4s]"></div>
                </div>
              </div>
            )}
            <div ref={chatEndRef} />
          </div>

          <div className="p-4 bg-slate-50 border-t border-slate-100">
            <div className="relative flex items-center">
              <input 
                type="text"
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyPress={(e) => e.key === 'Enter' && handleSend()}
                placeholder={t.assistant.placeholder}
                className="w-full bg-white px-5 py-3 rounded-full text-xs border border-slate-200 focus:outline-none focus:ring-2 focus:ring-[#1f7a8c]/20 pr-12"
              />
              <button 
                onClick={handleSend}
                className="absolute right-2 w-8 h-8 bg-[#0b3b52] text-white rounded-full flex items-center justify-center hover:bg-[#1f7a8c] transition-colors"
              >
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M13 5l7 7-7 7M5 5l7 7-7 7" /></svg>
              </button>
            </div>
          </div>
        </div>
      )}

      <button 
        onClick={() => setIsOpen(!isOpen)}
        className="w-16 h-16 bg-[#0b3b52] rounded-full shadow-2xl flex items-center justify-center text-[#CBA76B] hover:scale-110 active:scale-95 transition-all group"
      >
        <div className="relative">
          <svg className="w-8 h-8 group-hover:rotate-12 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M8 10h.01M12 10h.01M16 10h.01M21 12c0 4.418-4.03 8-9 8a9.863 9.863 0 01-4.255-.949L3 20l1.395-3.72C3.512 15.042 3 13.574 3 12c0-4.418 4.03-8 9-8s9 3.582 9 8z" />
          </svg>
          <span className="absolute -top-1 -right-1 w-4 h-4 bg-red-500 border-2 border-[#0b3b52] rounded-full animate-pulse"></span>
        </div>
      </button>
    </div>
  );
});

// --- COMPONENTE DE MAPA ---
const SatelliteMap = memo(({ t }: { t: TranslationStrings }) => {
  const mapRef = useRef<HTMLDivElement>(null);
  const apalanchiiLocation = { lat: 12.2023, lng: -72.1154 };

  useEffect(() => {
    const initMap = () => {
      if (mapRef.current && window.google) {
        const map = new window.google.maps.Map(mapRef.current, {
          center: apalanchiiLocation,
          zoom: 17,
          mapTypeId: 'satellite',
          disableDefaultUI: false,
          zoomControl: true,
          mapTypeControl: false,
          streetViewControl: false,
          fullscreenControl: true,
          gestureHandling: 'cooperative',
          styles: [{ featureType: "poi", elementType: "labels", stylers: [{ visibility: "off" }] }]
        });

        const marker = new window.google.maps.Marker({
          position: apalanchiiLocation,
          map: map,
          title: "Apalanchii Hospedaje y Restaurante",
          animation: window.google.maps.Animation.DROP
        });

